        .ns-title.pink { color: var(--secondary); }
        .ns-title.pink::before { content: '🎀'; }
        .kv-row { display: flex; justify-content: space-between; font-size: 13px; margin-bottom: 8px; padding-bottom: 4px; border-bottom: 1px dashed rgba(0,0,0,0.05);}
