        .hc-btn { background: linear-gradient(135deg, var(--primary), var(--secondary)); color: #fff; border: none; padding: 10px 20px; border-radius: 20px; font-weight: 800; font-size: 14px; cursor: pointer; transition: all 0.3s ease; box-shadow: 0 4px 15px rgba(0,0,0,0.1); }
        .hc-btn:hover:not(:disabled) { transform: translateY(-2px) scale(1.05); box-shadow: 0 6px 20px rgba(0,0,0,0.2); }
        .hc-btn:active:not(:disabled) { transform: scale(0.95); }
        .hc-btn:disabled { background: var(--text-light); opacity: 0.5; cursor: not-allowed; box-shadow: none; }

        /* 模态框 */
        .global-overlay { position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background: rgba(0,0,0,0.4); backdrop-filter: blur(3px); z-index: 9998; opacity: 0; pointer-events: none; transition: all 0.3s ease; }
        .global-overlay.show { opacity: 1; pointer-events: auto; }
        .modal { position: fixed; top: 50%; left: 50%; transform: translate(-50%, -40%) scale(0.9); width: 90%; max-width: 380px; padding: 25px; z-index: 9999; opacity: 0; pointer-events: none; transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275); max-height: 85vh; overflow-y: auto; }
        .modal.show { opacity: 1; pointer-events: auto; transform: translate(-50%, -50%) scale(1); }
        .m-close { position: absolute; top: 15px; right: 15px; cursor: pointer; color: var(--text-light); font-size: 20px; width: 30px; height: 30px; display: flex; justify-content: center; align-items: center; border-radius: 50%; background: var(--bg-main); transition: all 0.2s; }
        .m-close:hover { background: var(--danger); color: #fff; transform: rotate(90deg); }

        /* 地图 */
        .map-viewport { width: 100%; height: 350px; background: #e0f2fe; border: 2px solid var(--border-color); border-radius: var(--card-radius); overflow: hidden; position: relative; cursor: grab; touch-action: none; box-shadow: inset 0 0 20px rgba(0,0,0,0.05); }
        .map-viewport:active { cursor: grabbing; }
        .map-container { position: absolute; transform-origin: 0 0; transition: transform 0.1s ease-out;}
        .map-canvas { width: 1200px; height: 900px; background-size: 100% 100%; position: relative; }
        .map-controls { position: absolute; bottom: 15px; right: 15px; display: flex; flex-direction: column; gap: 10px; z-index: 50; }
        .zoom-btn { width: 40px; height: 40px; background: rgba(255,255,255,0.9); border: 2px solid var(--primary); color: var(--primary); border-radius: 50%; font-size: 22px; font-weight: bold; display: flex; justify-content: center; align-items: center; cursor: pointer; box-shadow: 0 4px 10px rgba(0,0,0,0.1); backdrop-filter: blur(5px); transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275); }
        .zoom-btn:hover { background: var(--primary); color: #fff; transform: scale(1.1); }
        .zoom-btn:active { transform: scale(0.9); }
        .map-node { position: absolute; transform: translate(-50%, -50%); z-index: 10; display: flex; flex-direction: column; align-items: center; padding: 10px; cursor: pointer;}
        .node-dot { width: 16px; height: 16px; border-radius: 50%; background: #fff; border: 4px solid var(--primary); box-shadow: 0 0 10px rgba(0,0,0,0.1); transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);}
        .node-dot:hover { transform: scale(1.5); background: var(--primary); border-color: #fff; box-shadow: 0 0 15px var(--primary);}
        .node-hero { width: 24px; height: 24px; background: var(--gold); clip-path: polygon(50% 0%, 61% 35%, 98% 35%, 68% 57%, 79% 91%, 50% 70%, 21% 91%, 32% 57%, 2% 35%, 39% 35%); animation: pulseGlow 2s infinite; }
        .node-npc { width: 14px; height: 14px; background: var(--secondary); border-radius: 50%; border: 3px solid #fff; box-shadow: 0 0 10px var(--secondary); }
        .node-npc-wrap { display: none; transition: opacity 0.3s ease; }
        .node-npc-wrap.show { display: flex; animation: fadeInScale 0.5s ease; }
        .node-label { margin-top: 6px; font-size: 12px; color: var(--text-main); background: rgba(255,255,255,0.9); padding: 4px 8px; border-radius: 12px; border: 1px solid var(--border-color); white-space: nowrap; font-weight: 800; box-shadow: var(--shadow-sm); backdrop-filter: blur(2px); transition: all 0.2s ease; }
