        .q-common { color: #64748b; } .q-rare { color: #3b82f6; } .q-epic { color: #c084fc; } .q-legendary { color: #fbbf24; text-shadow: 0 0 5px rgba(251, 191, 36, 0.3);}
    </style>
</head>
<body>
