    window.pendingTestPatches = [];
    window.npcImageCache = {};
    window.trackedNpcs = new Set();
    window.currentStatData = null;

    const DB_NAME = 'FateSysDB_Preview';
    const STORE_NPC = 'npcPicStore';
    const STORE_MAP = 'mapBgStore';

    function initDB() {
        return new Promise((resolve, reject) => {
            const request = indexedDB.open(DB_NAME, 2);
            request.onupgradeneeded = (e) => {
                const db = e.target.result;
                if (!db.objectStoreNames.contains(STORE_NPC)) db.createObjectStore(STORE_NPC);
                if (!db.objectStoreNames.contains(STORE_MAP)) db.createObjectStore(STORE_MAP);
            };
            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(request.error);
        });
    }

    const LocalImageStore = {
        save: async function(name, b64) {
            const db = await initDB();
            return new Promise((resolve, reject) => {
                const tx = db.transaction(STORE_NPC, 'readwrite');
                if (b64 === null) tx.objectStore(STORE_NPC).delete(name);
                else tx.objectStore(STORE_NPC).put(b64, name);
                tx.oncomplete = () => resolve();
            });
        },
        getAll: async function() {
            const db = await initDB();
            return new Promise((resolve) => {
                const tx = db.transaction(STORE_NPC, 'readonly');
                const store = tx.objectStore(STORE_NPC);
                const req = store.getAll();
                const reqKeys = store.getAllKeys();
                req.onsuccess = () => {
                    reqKeys.onsuccess = () => {
                        let res = {};
                        if(reqKeys.result) reqKeys.result.forEach((k, i) => res[k] = req.result[i]);
                        resolve(res);
                    }
                }
            });
        }
    };

    async function saveMapToDB(dataUrl) {
        const db = await initDB();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(STORE_MAP, 'readwrite');
            tx.objectStore(STORE_MAP).put(dataUrl, 'currentMapBg');
            tx.oncomplete = () => resolve();
            tx.onerror = () => reject(tx.error);
        });
    }

    async function getMapFromDB() {
        const db = await initDB();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(STORE_MAP, 'readonly');
            const request = tx.objectStore(STORE_MAP).get('currentMapBg');
            request.onsuccess = () => resolve(request.result);
            request.onerror = () => reject(tx.error);
        });
    }

    async function clearMapFromDB() {
        const db = await initDB();
        return new Promise((resolve, reject) => {
            const tx = db.transaction(STORE_MAP, 'readwrite');
            tx.objectStore(STORE_MAP).delete('currentMapBg');
            tx.oncomplete = () => resolve();
            tx.onerror = () => reject(tx.error);
        });
    }

    const DEFAULT_MAP_BG = '';

    window.applySavedMapBg = async function() {
        try {
            const urlBg = localStorage.getItem('fate_map_bg_url');
            if (urlBg) { document.getElementById('canvas').style.backgroundImage = `url('${urlBg}')`; return; }
            const localBg = await getMapFromDB();
            if (localBg) { document.getElementById('canvas').style.backgroundImage = `url('${localBg}')`; }
            else { document.getElementById('canvas').style.backgroundImage = `url('${DEFAULT_MAP_BG}')`; }
        } catch (e) {
            document.getElementById('canvas').style.backgroundImage = `url('${DEFAULT_MAP_BG}')`;
        }
    }

    const HERO_EQUIP_PARTS = ['头部', '身体', '足部', '饰品', '主灵装', '副灵装'];

    function getQClass(q) {
        if(!q) return 'q-common';
        if(q.includes('稀有') || q.includes('精良')) return 'q-rare';
        if(q.includes('史诗')) return 'q-epic';
        if(q.includes('传说') || q.includes('神话')) return 'q-legendary';
        return 'q-common';
    }

    function getProp(obj, path, defaultValue) {
        const keys = path.split('.');
        let result = obj;
        for (let key of keys) {
            if (result && typeof result === 'object' && key in result) {
                result = result[key];
            } else {
                return defaultValue;
            }
        }
        return result !== undefined ? result : defaultValue;
    }

    window.switchPage = function(pageId, btn) {
        document.querySelectorAll('.nav-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
        document.getElementById(pageId).classList.add('active');
        if(pageId === 'p-map') { updateMapBounds(); applyMapTransform(); }
    };

    window.toggleAccordion = function(el) {
        const body = el.nextElementSibling;
        if(body.style.display === 'block') {
            body.style.display = 'none';
        } else {
            body.style.display = 'block';
        }
    };

