    window.deleteNpc = function(e, name) {
        e.stopPropagation();
        if(confirm(`确定要从状态栏和世界中彻底移除NPC [${name}] 吗？`)) {
            window.pendingTestPatches.push(`移除NPC [${name}]`); updateHijack();
        }
