    window.queueAction = function(act, name, part) {
        let op = "";
        let sd = window.currentStatData; if (!sd) return;

        if (act === '卸下') {
            op = `将部位[${part}]的[${name}]卸下放入背包`;
            if (sd.主角 && sd.主角.着装 && sd.主角.着装[part]) {
                let item = sd.主角.着装[part];
                sd.主角.着装[part] = { 名称: '空置', 品质: '普通', 描述: '' };
                sd.主角.背包 = sd.主角.背包 || {}; sd.主角.背包['装备'] = sd.主角.背包['装备'] || {};
                sd.主角.背包['装备'][name] = { ...item, 类型: '装备', 部位: part, 数量: 1 };
            }
        } else if (act === '装备') {
            op = `将背包中的[${name}]装备到[${part}]`;
            if (sd.主角 && sd.主角.背包) {
                let item = null;
                for (let cat in sd.主角.背包) { if (sd.主角.背包[cat][name]) { item = sd.主角.背包[cat][name]; delete sd.主角.背包[cat][name]; break; } }
                if (item && sd.主角.着装) {
                    let oldItem = sd.主角.着装[part];
                    if (oldItem && oldItem.名称 !== '空置') {
                        sd.主角.背包['装备'] = sd.主角.背包['装备'] || {};
                        sd.主角.背包['装备'][oldItem.名称] = { ...oldItem, 类型: '装备', 部位: part, 数量: 1 };
                    }
                    sd.主角.着装[part] = { ...item, 名称: name, 类型: '装备', 部位: part };
                }
            }
        } else if (act === '使用') {
            op = `使用物品[${name}]`;
            if (sd.主角 && sd.主角.背包) {
                for (let cat in sd.主角.背包) { if (sd.主角.背包[cat][name]) { sd.主角.背包[cat][name].数量 -= 1; if (sd.主角.背包[cat][name].数量 <= 0) delete sd.主角.背包[cat][name]; break; } }
            }
        } else if (act === '丢弃') {
            op = `丢弃物品[${name}]`;
            if (sd.主角 && sd.主角.背包) {
                for (let cat in sd.主角.背包) { if (sd.主角.背包[cat][name]) { delete sd.主角.背包[cat][name]; break; } }
            }
        }
        window.pendingTestPatches.push(op); updateHijack(); closeModal(); populateCharacterData(false);
    };

