    };
    window.handleMapBgUpload = (e) => {
        const file = e.target.files[0]; if(!file) return;
        const reader = new FileReader();
        reader.onload = async (ev) => {
            try { await saveMapToDB(ev.target.result); localStorage.removeItem('fate_map_bg_url'); window.applySavedMapBg(); window.closeModal(); } catch(err) { alert('存入失败: ' + err.message); }
        }
