    };
    window.resetMapBg = async () => { localStorage.removeItem('fate_map_bg_url'); await clearMapFromDB(); window.applySavedMapBg(); window.closeModal(); };
    window.exportMapData = () => {
        let nodesToExport = DEFAULT_LOCATIONS;
        try { const savedNodes = localStorage.getItem('fate_map_nodes'); if (savedNodes) nodesToExport = JSON.parse(savedNodes); } catch(e) {}
        const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(nodesToExport, null, 2));
