        let d = currentLocations.find(loc => loc.n === name);
        if(!d) { d = DEFAULT_LOCATIONS.find(loc => loc.n === name); if(!d) return; }
        document.getElementById('cTitle').innerText = name; document.getElementById('cRegion').innerText = d.r; document.getElementById('cType').innerText = d.t;
        const safeEl = document.getElementById('cSafe'); safeEl.innerText = d.s; safeEl.style.backgroundColor = d.c;
        document.getElementById('cDesc').innerText = d.d;
        document.getElementById('overlay').classList.add('show'); document.getElementById('cityModal').classList.add('show');
    };

    let scale = 1.0, panX = 0, panY = 0, isDragging = false, startX, startY;
    let initialPinchDistance = null, initialScale = scale, lastTapTime = 0, vp, container;
    const CANVAS_W = 1200, CANVAS_H = 900; let minScale = 0.5;

    function initMapEngine() {
        vp = document.getElementById('viewport'); container = document.getElementById('map-container');
        if(!vp) return;
        vp.addEventListener('mousedown', handleMapStart); vp.addEventListener('touchstart', handleMapStart, {passive: false});
        window.addEventListener('mousemove', handleMapMove); window.addEventListener('touchmove', handleMapMove, {passive: false});
        window.addEventListener('mouseup', handleMapEnd); window.addEventListener('touchend', handleMapEnd);
        vp.addEventListener('wheel', e => { e.preventDefault(); zoomMap(e.deltaY > 0 ? -0.1 : 0.1); }, {passive: false});
    }
    function updateMapBounds() {
        if(!vp) return;
        const vpRect = vp.getBoundingClientRect(); minScale = Math.max(vpRect.width / CANVAS_W, vpRect.height / CANVAS_H);
        if (scale < minScale) scale = minScale;
        const scaledW = CANVAS_W * scale, scaledH = CANVAS_H * scale;
        const minX = vpRect.width - scaledW, minY = vpRect.height - scaledH;
        panX = Math.max(minX, Math.min(0, panX)); panY = Math.max(minY, Math.min(0, panY));
    }
    function getPointerPos(e) { return (e.touches && e.touches.length > 0) ? { x: e.touches[0].clientX, y: e.touches[0].clientY } : { x: e.clientX, y: e.clientY }; }
    function getPinchDist(e) { return (e.touches.length < 2) ? 0 : Math.hypot(e.touches[0].clientX - e.touches[1].clientX, e.touches[0].clientY - e.touches[1].clientY); }
    function handleMapStart(e) {
        if(e.target.closest('.map-controls')) return;
        const node = e.target.closest('.map-node');
        if (node && (!e.touches || e.touches.length === 1)) {
            const now = Date.now(); if (now - lastTapTime < 300) return; lastTapTime = now;
            let nId = node.getAttribute('data-id');
            if(nId) {
                let currentLocations = [];
                try { const savedNodes = localStorage.getItem('fate_map_nodes'); if (savedNodes) currentLocations = JSON.parse(savedNodes); } catch(err) {}
                let c = currentLocations.find(x => String(x.id) === String(nId)) || DEFAULT_LOCATIONS.find(x => String(x.id) === String(nId));
                if(c) openCityModal(c.n);
            }
        }
        if(e.touches && e.touches.length === 2) { isDragging = false; initialPinchDistance = getPinchDist(e); initialScale = scale; }
        else { isDragging = true; const pos = getPointerPos(e); startX = pos.x - panX; startY = pos.y - panY; }
        vp.style.cursor = 'grabbing'; if(e.cancelable && !node) e.preventDefault();
    }
    function handleMapMove(e) {
        if(e.touches && e.touches.length === 2) {
            if(!initialPinchDistance) return;
            let newScale = initialScale * (getPinchDist(e) / initialPinchDistance); newScale = Math.max(minScale, Math.min(newScale, 2.5));
            const vpRect = vp.getBoundingClientRect(); const cx = vpRect.width/2, cy = vpRect.height/2;
            panX = cx - (cx - panX) * (newScale / scale); panY = cy - (cy - panY) * (newScale / scale);
            scale = newScale; updateMapBounds(); applyMapTransform(); if(e.cancelable) e.preventDefault(); return;
        }
        if(!isDragging) return;
        const pos = getPointerPos(e); panX = pos.x - startX; panY = pos.y - startY;
        updateMapBounds(); applyMapTransform(); if(e.cancelable) e.preventDefault();
    }
    function handleMapEnd() { isDragging = false; initialPinchDistance = null; if(vp) vp.style.cursor = 'grab'; }
    window.zoomMap = function(delta) {
        const oldScale = scale; scale = Math.max(minScale, Math.min(scale + delta, 2.5));
        const vpRect = vp.getBoundingClientRect(); const cx = vpRect.width / 2, cy = vpRect.height / 2;
        panX = cx - (cx - panX) * (scale / oldScale); panY = cy - (cy - panY) * (scale / oldScale);
        updateMapBounds(); applyMapTransform();
    }
    function applyMapTransform() { if(container) container.style.transform = `translate(${panX}px, ${panY}px) scale(${scale})`; }

    async function init() {
        loadSavedTheme();
        if(typeof waitGlobalInitialized === 'function') await waitGlobalInitialized('Mvu');
        initMapEngine();
        applySavedMapBg();
        await populateCharacterData(true);
        setTimeout(() => { updateMapBounds(); applyMapTransform(); }, 100);

        if(typeof eventOn === 'function' && typeof Mvu !== 'undefined') {
            eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => { populateCharacterData(true); });
        }
    }

    if(typeof errorCatched === 'function') {
        $(errorCatched(init));
    } else {
        $(document).ready(init);
    }
</script>
