        @keyframes pulse { 0% { opacity: 0.5; } 50% { opacity: 1; } 100% { opacity: 0.5; } }

        .relic-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(140px, 1fr)); gap: 10px; }
        .relic-card { background: rgba(0,0,0,0.5); border: 1px solid rgba(255,255,255,0.1); border-radius: 8px; padding: 12px; cursor: pointer; transition: 0.3s; display: flex; flex-direction: column; }
        .relic-card:hover { border-color: var(--primary); transform: translateY(-2px); }
        .relic-card.selected { border-color: var(--gold); background: rgba(234, 179, 8, 0.1); box-shadow: 0 0 10px rgba(234, 179, 8, 0.2); }
        .r-name { font-size: 13px; font-weight: bold; color: #fff; margin-bottom: 4px; }
        .r-tag { font-size: 9px; padding: 2px 4px; background: rgba(255,255,255,0.1); border-radius: 3px; color: var(--gold); display: inline-block; margin-bottom: 6px; }
        .r-desc { font-size: 11px; color: var(--text-muted); line-height: 1.4; flex: 1; }
