    background-image: url('');
}
        .map-node { position: absolute; display: flex; flex-direction: column; align-items: center; transform: translate(-50%, -50%); cursor: pointer; z-index: 10; padding: 5px; }
        .node-dot { width: 12px; height: 12px; border-radius: 50%; background: #000; border: 2px solid var(--text-muted); transition: 0.3s; }
        .map-node:hover .node-dot { border-color: var(--primary); box-shadow: 0 0 10px var(--primary); }
        .map-node.selected .node-dot { border-color: var(--gold); background: var(--gold); box-shadow: 0 0 15px var(--gold); transform: scale(1.3); }
        .node-label { font-size: 10px; color: #fff; background: rgba(0,0,0,0.8); padding: 2px 4px; border-radius: 4px; margin-top: 4px; white-space: nowrap; border: 1px solid rgba(255,255,255,0.1); }
        .map-node.selected .node-label { border-color: var(--gold); color: var(--gold); }
        .map-controls { position: absolute; bottom: 10px; right: 10px; display: flex; flex-direction: column; gap: 5px; z-index: 20; }
        .zoom-btn { width: 30px; height: 30px; background: rgba(0,0,0,0.7); border: 1px solid var(--border-color); color: var(--primary); display: flex; justify-content: center; align-items: center; cursor: pointer; border-radius: 4px; font-weight: bold; }

