</head>
<body>

<div class="sys-container">
    <div class="header">
        <div class="sys-title">FATE SYSTEM</div>
        <div class="sys-subtitle">Initialization Protocol</div>
    </div>

    <!-- API 配置按钮 -->
    <div class="api-btn" onclick="toggleApi()">⚙️ API 配置</div>
    <div class="api-panel" id="api_panel">
        <div style="font-size:12px; font-weight:bold; color:#fff; margin-bottom:10px;">外部 API 配置 (用于盲盒抽卡)</div>
        <div class="api-input-group">
            <label class="api-label">API URL</label>
            <input type="text" class="api-input" id="api_url" placeholder="https://api.openai.com/v1">
        </div>
        <div class="api-input-group">
            <label class="api-label">API Key</label>
            <input type="password" class="api-input" id="api_key" placeholder="sk-...">
        </div>
        <div class="api-input-group">
            <label class="api-label">
                <span>Model</span>
                <span class="fetch-btn" id="fetch_model_btn" onclick="fetchModels()">拉取模型</span>
            </label>
            <input type="text" class="api-input" id="api_model" list="model_list" placeholder="gpt-4o-mini 或下拉选择">
            <datalist id="model_list"></datalist>
        </div>
        <div class="api-save-btn" onclick="saveApi()">保存配置并关闭</div>
    </div>

    <div class="global-overlay" id="overlay" onclick="closeModals()"></div>

    <!-- 城市详情模态框 -->
    <div class="modal" id="cityModal">
        <div class="m-close" onclick="closeModals()">✖</div>
        <div style="font-size:16px; font-weight:bold; color:#fff; margin-bottom:5px;" id="m_name">地点名</div>
        <div style="font-size:11px; color:var(--primary); margin-bottom:10px;" id="m_type">类型</div>
        <div style="display:flex; gap:10px; margin-bottom:12px; font-size:10px;">
            <span style="background:rgba(255,255,255,0.1); padding:2px 6px; border-radius:3px; color:var(--gold);" id="m_danger">危险度</span>
            <span style="background:rgba(255,255,255,0.1); padding:2px 6px; border-radius:3px; color:var(--text-muted);" id="m_faction">势力</span>
        </div>
        <div style="font-size:12px; color:var(--text-muted); line-height:1.5; margin-bottom:15px;" id="m_desc">描述...</div>
        <div class="btn btn-next" style="width:100%; text-align:center; padding:8px;" onclick="confirmLoc()">锁定此坐标</div>
    </div>

    <!-- 自定义底图模态框 -->
    <div class="modal" id="mapConfigModal">
        <div class="m-close" onclick="closeModals()">✖</div>
        <div style="font-size:14px; font-weight:bold; color:var(--primary); margin-bottom:10px;">自定义大地图底图</div>
        <div style="font-size:11px; color:var(--text-muted); margin-bottom:15px;">你可以使用网络链接或直接上传本地图片替换原有地图。上传的图片将被保存在浏览器的 IndexedDB 数据库中。</div>

        <div style="font-size: 11px; color: var(--gold); margin-bottom: 6px;">方案一：网络 URL</div>
        <input type="text" id="map_bg_url" placeholder="https://..." class="sys-input" style="margin-bottom: 10px;">
        <div class="btn btn-next" style="width:100%; text-align:center; padding:8px; margin-bottom: 15px;" onclick="saveMapBgUrl()">保存网络链接</div>

        <div style="font-size: 11px; color: var(--primary); margin-bottom: 6px;">方案二：本地上传</div>
        <input type="file" id="map_bg_file" accept="image/*" style="display:none;" onchange="handleMapBgUpload(event)">
        <div class="btn" style="background:rgba(59,130,246,0.1); border:1px dashed var(--primary); color:var(--primary); width:100%; text-align:center; margin-bottom:10px;" onclick="document.getElementById('map_bg_file').click()">📁 选择本地图片</div>

        <div class="btn" style="background:transparent; border:1px solid var(--secondary); color:var(--secondary); width:100%; text-align:center;" onclick="resetMapBg()">恢复默认地图</div>
    </div>

    <!-- Page 1: 路线 -->
    <div class="page active" id="page-1">
        <div class="sec-title">STEP 1. 确立身份终端</div>
        <div class="route-card selected" onclick="selectRoute('preset')" id="route-preset">
            <div class="route-name">【预设档案】{{user}}</div>
            <div class="route-desc">BRACE顶级特工。为了调查铃木家族而来。自带顶级灵装「残火之楔」。降临点锁定于废弃工业区。</div>
        </div>
        <div class="route-card" onclick="selectRoute('custom')" id="route-custom">
            <div class="route-name">【自定义档案】未知觉醒者</div>
            <div class="route-desc">脱离监控的未知个体。手动录入信息并分配初始点数。资源从零开始。</div>
        </div>
        <div class="preset-box show" id="preset-preview">
            <div style="font-size:11px; color:var(--gold); margin-bottom:10px; font-weight:bold;">[系统已锁定高阶预设数据]</div>
            <div class="kv-line"><span class="kv-k">基础</span><span class="kv-v">男 / 28岁 / BRACE顶级特工</span></div>
            <div class="kv-line"><span class="kv-k">初始资金</span><span class="kv-v" style="color:var(--gold);">999,999,999 CNY</span></div>
            <div class="kv-line"><span class="kv-k">核心能力</span><span class="kv-v">极高智慧 / 灵装高契合度</span></div>
        </div>
    </div>

    <!-- Page 2: 自定义填写 -->
    <div class="page" id="page-2">
        <div class="sec-title">STEP 2. 录入主体数据</div>
        <div class="input-group"><label class="input-label">真名 (Name)</label><input type="text" class="sys-input" id="c_name" placeholder="输入姓名..."></div>
        <div class="flex-row">
            <div class="input-group flex-1"><label class="input-label">性别 (Gender)</label><select class="sys-input" id="c_sex"><option value="男">男</option><option value="女">女</option></select></div>
            <div class="input-group flex-1"><label class="input-label">年龄 (Age)</label><input type="number" class="sys-input" id="c_age" value="17"></div>
        </div>
        <div class="input-group"><label class="input-label">表面身份 (Identity)</label><input type="text" class="sys-input" id="c_job" placeholder="例如: 普通高中生"></div>
    </div>

    <!-- Page 3: 属性加点 -->
    <div class="page" id="page-3">
        <div class="sec-title">STEP 3. 神经突触强化</div>
        <div class="pt-bar"><span>可用属性点数</span><span id="pt_left" style="color:var(--gold);">20</span></div>
        <div id="stats_container"></div>
    </div>

    <!-- Page 4: 灵装盲盒 -->
    <div class="page" id="page-4">
        <div class="sec-title">STEP 4. 提取初始灵装</div>
        <div style="font-size:11px; color:var(--text-muted); margin-bottom:10px;">
            <span id="gacha_tip">你可以在黑市残骸中挑选一件初始灵装。</span>
        </div>
        <div class="gacha-btn" id="gacha_btn" onclick="rollRelics()">🎲 链接外部 API 抽取黑市盲盒 (随机6件)</div>
        <div class="relic-grid" id="relic_grid"></div>
    </div>

    <!-- Page 5: 地图 -->
    <div class="page" id="page-5">
        <div class="sec-title">STEP 5. 锁定降临坐标</div>
        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px; flex-wrap:wrap; gap:10px;">
            <span style="font-size:11px; color:var(--text-muted);">拖拽平移 | 滚轮缩放 | 点击节点查看</span>
            <div style="display:flex; gap:12px;">
                <span style="font-size:11px; color:var(--primary); cursor:pointer;" onclick="document.getElementById('map_data_import_init').click()">📥 导入</span>
                <span style="font-size:11px; color:var(--primary); cursor:pointer;" onclick="exportMapData()">📤 导出</span>
                <span style="font-size:11px; color:var(--primary); cursor:pointer;" onclick="openMapConfig()">🖼️ 自定义底图</span>
                <input type="file" id="map_data_import_init" accept=".json" style="display:none;" onchange="importMapData(event)">
            </div>
        </div>
        <div class="map-viewport" id="viewport">
            <div class="map-canvas" id="canvas"></div>
            <div class="map-controls">
                <div class="zoom-btn" onclick="zoomMap(0.2)">+</div>
                <div class="zoom-btn" onclick="zoomMap(-0.2)">-</div>
            </div>
        </div>
        <div style="font-size:12px; text-align:center; color:var(--gold);" id="loc_display">未锁定坐标</div>
    </div>

    <div class="nav-bar">
        <button class="btn btn-prev" id="btn-prev" onclick="go(-1)" disabled>BACK</button>
        <button class="btn btn-next" id="btn-next" onclick="go(1)">NEXT</button>
    </div>
</div>

