    /* API 及本地数据库 */
    const DB_NAME = 'FateMapDB';
    const STORE_NAME = 'bgStore';
    function initDB() { return new Promise((res, rej) => { const req = indexedDB.open(DB_NAME, 1); req.onupgradeneeded = e => { if(!e.target.result.objectStoreNames.contains(STORE_NAME)) e.target.result.createObjectStore(STORE_NAME); }; req.onsuccess = () => res(req.result); req.onerror = () => rej(req.error); }); }
    async function saveMap(b64) { const db = await initDB(); return new Promise((res) => { const tx = db.transaction(STORE_NAME, 'readwrite'); tx.objectStore(STORE_NAME).put(b64, 'bg'); tx.oncomplete = res; }); }
    async function getMap() { const db = await initDB(); return new Promise((res) => { const tx = db.transaction(STORE_NAME, 'readonly'); const req = tx.objectStore(STORE_NAME).get('bg'); req.onsuccess = () => res(req.result); }); }
    async function clearMap() { const db = await initDB(); return new Promise((res) => { const tx = db.transaction(STORE_NAME, 'readwrite'); tx.objectStore(STORE_NAME).delete('bg'); tx.oncomplete = res; }); }

    function toggleApi() { $('api_panel').classList.toggle('show'); }
    function saveApi() {
        localStorage.setItem('f_url', $('api_url').value.trim());
        localStorage.setItem('f_key', $('api_key').value.trim());
        localStorage.setItem('f_mod', $('api_model').value.trim());
        toggleApi();
    }
    function loadApi() {
        $('api_url').value = localStorage.getItem('f_url') || 'https://api.openai.com/v1';
        $('api_key').value = localStorage.getItem('f_key') || '';
        $('api_model').value = localStorage.getItem('f_mod') || 'gpt-4o-mini';
    }

    // 新增：拉取模型列表功能
    async function fetchModels() {
        const btn = $('fetch_model_btn');
        const url = $('api_url').value.trim();
        const key = $('api_key').value.trim();

        if(!url || !key) {
            alert("请先填写 API URL 和 API Key！");
            return;
        }

        try {
            btn.classList.add('loading');
            btn.innerText = "拉取中...";

            // 处理 URL：如果是带有 /chat/completions 结尾，要去掉。然后拼上 /models
            let fetchUrl = url;
            if(fetchUrl.endsWith('/chat/completions')) {
                fetchUrl = fetchUrl.replace('/chat/completions', '');
            }
            if(!fetchUrl.endsWith('/v1') && fetchUrl.includes('api.openai.com')) {
                fetchUrl = fetchUrl.replace(/\/$/, '') + '/v1';
            }
            fetchUrl = fetchUrl.replace(/\/$/, '') + '/models';

            const res = await fetch(fetchUrl, {
                method: 'GET',
                headers: { 'Authorization': `Bearer ${key}` }
            });

            if(!res.ok) throw new Error("HTTP " + res.status);

            const data = await res.json();
            if(data && data.data && Array.isArray(data.data)) {
                let html = '';
                data.data.forEach(m => {
                    html += `<option value="${m.id}">`;
                });
                $('model_list').innerHTML = html;
                alert("拉取成功！可以直接在下拉列表中选择模型了。");
            } else {
                throw new Error("返回数据格式不符合标准");
            }
        } catch(e) {
            alert("获取模型失败: " + e.message + "\n请确认API地址支持 /models 接口或直接手动填写。");
        } finally {
            btn.classList.remove('loading');
            btn.innerText = "拉取模型";
        }
    }

