    async function rollRelics() {
        const btn = $('gacha_btn');
        const url = $('api_url').value.trim(); const key = $('api_key').value.trim(); const mod = $('api_model').value.trim();
        if(!url || !key) { alert("请先在右上角配置 API URL 和 Key！"); return; }

        try {
            btn.classList.add('loading'); btn.innerText = "链接深网数据库中...";
            let fetchUrl = url; if(!fetchUrl.endsWith('/chat/completions')) fetchUrl = fetchUrl.replace(/\/$/, '') + '/chat/completions';

            const prompt = `你现在是《幻》世界的黑市商人。请提供6件形态各异的现代灵装（如打火机、耳机、眼药水等日常物品变异而来）。\n【强制要求】：只输出一个JSON数组格式，不要任何其他废话。格式如下：\n[{"name":"【物品名】", "desc":"功能描述(15字)", "curse":"使用代价(15字)", "part":"主灵装/副灵装/饰品/消耗品", "qual":"稀有/精良/史诗/传说", "passive":"被动词条(短)"}]`;

            const res = await fetch(fetchUrl, {
                method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${key}` },
                body: JSON.stringify({ model: mod, messages: [{ role: "user", content: prompt }], temperature: 0.9 })
            });
            if(!res.ok) throw new Error("HTTP " + res.status);
            const data = await res.json();
            let txt = data.choices[0].message.content.replace(/```json\s*/gi, '').replace(/```\s*$/gi, '').trim();
            const match = txt.match(/\[\s*{[\s\S]*}\s*\]/);
            if(!match) throw new Error("无法提取 JSON");
            const arr = JSON.parse(match[0]);
            renderRelics(arr);
            btn.innerText = "重新抽取黑市盲盒";
        } catch(e) {
            alert("抽取失败: " + e.message); btn.innerText = "🎲 链接外部 API 抽取黑市盲盒 (随机6件)";
        } finally { btn.classList.remove('loading'); }
    }

