    function importMapData(e) {
        const file = e.target.files[0]; if(!file) return;
        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const newLocs = JSON.parse(ev.target.result);
                if(Array.isArray(newLocs)) {
                    locations = newLocs;
                    localStorage.setItem('fate_map_nodes', JSON.stringify(newLocs));
                    alert('地图节点导入成功！');
                    renderMap();
                    // 检查当前选中节点是否存在，不存在则重置
                    if (!locations.find(l => l.n === selectedLocation)) {
                        selectedLocation = locations[0] ? locations[0].n : '未知坐标';
                        $('loc_display').innerText = `已锁定坐标: ${selectedLocation}`;
                    }
                } else {
                    alert('数据格式错误，必须是数组。');
                }
            } catch(err) { alert('解析失败: ' + err.message); }
        }
        reader.readAsText(file); e.target.value = '';
    }

    let scale = 1.0, panX = 0, panY = 0, isDragging = false, startX, startY;
    const CANVAS_W = 1200, CANVAS_H = 900;

    function constrainMap() {
        const vp = $('viewport');
        if(!vp) return;
        const vpRect = vp.getBoundingClientRect();

        const minScale = Math.max(vpRect.width / CANVAS_W, vpRect.height / CANVAS_H);
        if (scale < minScale) scale = minScale;
        if (scale > 3.0) scale = 3.0;

        const scaledW = CANVAS_W * scale;
        const scaledH = CANVAS_H * scale;

        const minX = vpRect.width - scaledW;
        const minY = vpRect.height - scaledH;

        panX = Math.max(minX, Math.min(0, panX));
        panY = Math.max(minY, Math.min(0, panY));
    }

    function applyTrans() {
        const vp = $('viewport');
        if(vp) constrainMap();
        $('canvas').style.transform = `translate(${panX}px, ${panY}px) scale(${scale})`;
    }

    function zoomMap(delta) {
        const vp = $('viewport');
        const oldScale = scale;
        scale += delta;
        const cx = vp.clientWidth / 2;
        const cy = vp.clientHeight / 2;
        panX = cx - (cx - panX) * (scale / oldScale);
        panY = cy - (cy - panY) * (scale / oldScale);
        applyTrans();
    }

    function renderMap() {
        let html = '';
        locations.forEach(l => {
            const isSel = l.n === selectedLocation ? 'selected' : '';
            html += `<div class="map-node ${isSel}" style="left:${l.x}%; top:${l.y}%;" onclick="openLoc(${l.id})">
                <div class="node-dot" style="border-color:${l.c};"></div>
                <div class="node-label">${l.n}</div>
            </div>`;
        });
        $('canvas').innerHTML = html;
    }

    let curLocObj = null;
    function openLoc(id) {
        const l = locations.find(x => String(x.id) === String(id)); if(!l) return;
        curLocObj = l;
        $('m_name').innerText = l.n; $('m_type').innerText = l.t;
        $('m_danger').innerText = l.s; $('m_danger').style.color = l.c;
        $('m_faction').innerText = l.r || l.f || '未知'; // 兼容旧版的f字段或新的r字段
        $('m_desc').innerText = l.d;
        $('overlay').classList.add('show'); $('cityModal').classList.add('show');
    }

    function confirmLoc() {
        if(curLocObj) { selectedLocation = curLocObj.n; renderMap(); $('loc_display').innerText = `已锁定坐标: ${selectedLocation}`; }
        closeModals();
    }

    function initMap() {
        const vp = $('viewport');
        // 尝试从状态栏的缓存中读取已同步的节点数据
        try {
            const savedNodes = localStorage.getItem('fate_map_nodes');
            if (savedNodes) locations = JSON.parse(savedNodes);
        } catch(e) {}

        // 鼠标拖拽
        vp.addEventListener('mousedown', e => { if(e.target.closest('.map-controls') || e.target.closest('.map-node')) return; isDragging=true; startX=e.clientX-panX; startY=e.clientY-panY; vp.style.cursor='grabbing'; });
        window.addEventListener('mousemove', e => { if(!isDragging) return; panX=e.clientX-startX; panY=e.clientY-startY; applyTrans(); });
        window.addEventListener('mouseup', () => { isDragging=false; vp.style.cursor='grab'; });
        vp.addEventListener('mouseleave', () => { isDragging=false; vp.style.cursor='grab'; });
        // 鼠标滚轮缩放
        vp.addEventListener('wheel', e => { e.preventDefault(); zoomMap(e.deltaY>0?-0.1:0.1); }, {passive:false});

        // 手机触摸支持
        vp.addEventListener('touchstart', e => { if(e.target.closest('.map-controls') || e.target.closest('.map-node')) return; if(e.touches.length===1){ isDragging=true; startX=e.touches[0].clientX-panX; startY=e.touches[0].clientY-panY; }});
        window.addEventListener('touchmove', e => { if(!isDragging || e.touches.length!==1) return; panX=e.touches[0].clientX-startX; panY=e.touches[0].clientY-startY; applyTrans(); });
        window.addEventListener('touchend', () => isDragging=false);

        const vpRect = vp.getBoundingClientRect();
        scale = Math.max(vpRect.width / CANVAS_W, vpRect.height / CANVAS_H);
        panX = (vpRect.width - CANVAS_W * scale) / 2;
        panY = (vpRect.height - CANVAS_H * scale) / 2;

        applyTrans();
        renderMap();
    }

    /* 流程控制 */
    function go(dir) {
        if(dir===1) {
            if(currentRoute==='custom' && currentPage===2 && (!$('c_name').value.trim() || !$('c_job').value.trim())) { alert("请填写姓名和身份！"); return; }
            if(currentPage===4 && !selectedRelic) { alert("请选择一件初始灵装！"); return; }
        }

        let target = currentPage + dir;
        if(currentRoute==='preset') {
            if(currentPage===1 && dir===1) target = 4; // 预设跳过 2,3
            if(currentPage===4 && dir===-1) target = 1;
        }

        if(target > 5) return finalizeInit();

        document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
        $('page-'+target).classList.add('active');
        currentPage = target;

        $('btn-prev').disabled = (currentPage===1);
        if(currentPage===5) {
            $('btn-next').innerText = 'INITIALIZE';
            $('btn-next').style.background = 'var(--secondary)';
            setTimeout(() => { constrainMap(); applyTrans(); }, 100);
        }
        else { $('btn-next').innerText = 'NEXT'; $('btn-next').style.background = 'var(--primary)'; }
    }

    function finalizeInit() {
        let patches = [];
        patches.push({ "op": "replace", "path": "/世界/当前地点", "value": selectedLocation });
        patches.push({ "op": "replace", "path": "/世界/当前时间", "value": "2024-09-01 22:00" });

        if(currentRoute === 'preset') {
