            patches.push({ "op": "replace", "path": "/主角/属性/体能", "value": 15 });
            patches.push({ "op": "replace", "path": "/主角/属性/精神", "value": 45 });
            patches.push({ "op": "replace", "path": "/主角/属性/灵感", "value": 35 });
            patches.push({ "op": "replace", "path": "/主角/属性/契合", "value": 50 });
            patches.push({ "op": "replace", "path": "/主角/属性/抗性", "value": 30 });
            patches.push({ "op": "replace", "path": "/主角/属性/交涉", "value": 40 });

            patches.push({ "op": "replace", "path": "/主角/着装/主灵装", "value": { "名称": "【残火之楔】", "品质": "A+", "描述": "超强的战斗型太刀灵装。", "被动词条": "可以切断灵装连接" } });
        } else {
            patches.push({ "op": "replace", "path": "/主角/基础/姓名", "value": $('c_name').value.trim() });
