            baseStats.forEach(s => { patches.push({ "op": "replace", "path": "/主角/属性/" + s, "value": customStats[s] }); });
        }

        if(selectedRelic) {
            const relObj = { "描述": selectedRelic.desc + " 代价: " + selectedRelic.curse, "品质": selectedRelic.qual, "被动词条": selectedRelic.passive };
            if(selectedRelic.part === '消耗品') {
                relObj.数量 = 1; relObj.类型 = "消耗品";
                patches.push({ "op": "insert", "path": `/主角/背包/特殊物资/${selectedRelic.name}`, "value": relObj });
            } else {
                relObj.名称 = selectedRelic.name;
                if(currentRoute === 'preset' && (selectedRelic.part === '主灵装' || selectedRelic.part === '副灵装')) {
                    relObj.数量 = 1; relObj.类型 = "装备"; relObj.部位 = selectedRelic.part;
                    patches.push({ "op": "insert", "path": `/主角/背包/战术物资/${selectedRelic.name}`, "value": relObj });
