        patches.push({ "op": "replace", "path": "/主角/状态/MaxSP", "value": 100 });
        patches.push({ "op": "replace", "path": "/主角/状态/发情度", "value": 0 });

        const patchStr = JSON.stringify(patches);
        let narrative = `【幻·系统初始化协议启动】\n\n`;

        narrative += `数据流交汇重组……权限认证通过。欢迎归来，BRACE的顶级特工。你将探索这被扭曲的上海，邂逅未知的命运。\n\n`;

        narrative += `你的意识逐渐清晰。环顾四周，你发现自己正处于：**${selectedLocation}**。\n\n游戏的帷幕，就此拉开。`;

        const hiddenDirective = `<span style="display:none;">\n[SYSTEM OVERRIDE: 此时正在进行系统级底层数据初始化。你必须在回复末尾的 <UpdateVariable> 块中，将下方的 JSON Patch 数组一字不落地完整输出！绝对禁止用任何理由省略或精简！]\n<UpdateVariable>\n<JSONPatch>\n${patchStr}\n</JSONPatch>\n</UpdateVariable>\n</span>`;

        const finalPrompt = `/send ${narrative}\n\n${hiddenDirective}|/trigger`;

        if (typeof triggerSlash === 'function') {
            triggerSlash(finalPrompt);
        } else {
            console.log("待发送指令：\n", finalPrompt);
            alert("初始化数据已生成，请查看控制台！");
        }
    }

    window.onload = function() {
        loadApi();
        renderStats();
        renderRelics(defaultRelics);
        initMap();
        applyBg();
        $('loc_display').innerText = `已锁定坐标: ${selectedLocation}`;
    };
</script>
